// Build HubSpot engagement note body from normalized meeting data
const d = $input.item.json;

const actionItemsText = (d.action_items || []).length > 0
  ? (d.action_items || []).map((a, i) => `${i+1}. ${a.owner || 'TBD'}: ${a.task}${a.deadline_mentioned ? ' (by ' + a.deadline_mentioned + ')' : ''}`).join('
')
  : 'None recorded';

const decisionsText = (d.decisions || []).length > 0
  ? (d.decisions || []).map((dec, i) => `${i+1}. ${dec}`).join('
')
  : 'None recorded';

const noteBody = `[Meeting Intelligence — Auto-generated]

Meeting: ${d.title}
Date: ${d.date}
Duration: ${d.duration_minutes || 'N/A'} min
Sentiment: ${d.sentiment}
Themes: ${(d.themes || []).join(', ')}

SUMMARY
${d.summary}

ACTION ITEMS
${actionItemsText}

DECISIONS
${decisionsText}

Transcript: ${d.source_url}`;

return {
  ...d,
  hubspot_note_body: noteBody
};

// Return confirmation shape
return {
  crm_write_status: 'ok',
  crm_record_id: $input.item.json?.id || null
};
